### 1. gRPC Service Interface (`pricing.proto`)

```proto
syntax = "proto3";

package startd8.bench.pricing.v1;

// Standard options for code generation across different languages.
option java_package = "com.startd8.bench.pricing.v1";
option java_multiple_files = true;
option go_package = "github.com/startd8/bench/pricing/v1;pricingv1";

// PricingService provides a stateless, exact-decimal price calculation engine.
// It is designed for high-performance financial and commerce systems where
// precision, auditability, and deterministic results are critical. The service
// operates as a pure function, ensuring that all data required for a
// calculation is provided within the request payload.
service PricingService {
  // ComputeBasket calculates the final prices for a collection of line items
  // based on a set of discounts, tax rules, and currency-specific rounding.
  // This RPC is a pure function; it performs no external data lookups or
  // state modifications.
  rpc ComputeBasket(ComputeBasketRequest) returns (ComputeBasketResponse);
}

// DiscountStrategy defines how multiple discount tiers are combined when applied
// to a single line item.
enum DiscountStrategy {
  // Strategy is not specified. Requests with this value will be rejected.
  DISCOUNT_STRATEGY_UNSPECIFIED = 0;
  // CHAIN: Multiplicative stacking. Each discount is applied sequentially to the
  // running subtotal. E.g., 10% off, then 5% off the newly discounted price.
  CHAIN = 1;
  // ADDITION: Additive stacking. All discount percentages are summed and
  // applied once to the original price. E.g., 10% + 5% = 15% off the original price.
  ADDITION = 2;
}

// DiscountKind specifies the fundamental nature of a discount.
enum DiscountKind {
  // Kind is not specified. Requests with this value will be rejected.
  DISCOUNT_KIND_UNSPECIFIED = 0;
  // PERCENTAGE: A percentage-based reduction from a base amount.
  PERCENTAGE = 1;
  // FIXED_AMOUNT: A fixed monetary reduction from a base amount.
  FIXED_AMOUNT = 2;
}

// RoundingMode determines the rounding behavior for monetary calculations at the
// precision specified by the currency scale.
enum RoundingMode {
  // Rounding mode is not specified. Requests with this value will be rejected.
  // The client must explicitly select a rounding mode.
  ROUNDING_MODE_UNSPECIFIED = 0;
  // HALF_UP: Rounds to the nearest neighbor. If equidistant from two neighbors,
  // it rounds away from zero (e.g., 2.5 -> 3, -2.5 -> -3). This is the
  // most common form of rounding.
  HALF_UP = 1;
  // HALF_EVEN: Rounds to the nearest neighbor. If equidistant, it rounds
  // towards the nearest neighbor with an even least significant digit. Also known
  // as "Banker's Rounding" (e.g., 2.5 -> 2, 3.5 -> 4).
  HALF_EVEN = 2;
}

// Currency defines the monetary context for calculation, including precision
// (scale) and rounding rules.
message Currency {
  // The ISO 4217 currency code (e.g., "USD", "EUR"). This is for metadata and
  // is not used in calculations.
  string code = 1;
  // The number of decimal places for the currency (the scale).
  // For USD, this would be 2. For JPY, it would be 0.
  uint32 scale = 2;
  // The rounding mode to apply for all intermediate and final calculations that
  // require rounding to the currency's scale.
  RoundingMode rounding = 3;
}

// Discount represents a single discount to be applied to a line item.
// It can be a percentage or a fixed amount and may have multiple tiers that
// are combined according to the request's DiscountStrategy.
message Discount {
  // The kind of discount (percentage or fixed amount).
  DiscountKind kind = 1;
  // A list of discount factors, represented as decimal strings.
  // For PERCENTAGE kind, these are percentages (e.g., "10.5" for 10.5%). Multiple
  // tiers can be applied based on the DiscountStrategy.
  // For FIXED_AMOUNT kind, only the first entry is used, representing a flat
  // monetary value to subtract. Subsequent entries are ignored.
  repeated string tier_factors = 2;
  // An optional cap on the total discount amount that can be applied by this
  // Discount message. If the calculated discount exceeds this value, it will be
  // clamped to this maximum. Represented as a decimal string. An empty or
  // missing string implies no maximum.
  string maximum_amount = 3;
}

// LineItem represents a single item in a shopping basket before pricing.
message LineItem {
  // A unique identifier for the product variant (Stock Keeping Unit).
  string sku = 1;
  // The quantity of the item, as a decimal string to support fractional units
  // (e.g., "1.5" kg).
  string quantity = 2;
  // The base price per single unit of the item.
  string unit_price = 3;
  // An optional promotional or "offer" price per single unit. If this price is
  // valid (positive and less than unit_price), it will be used as the starting
  // price for all calculations.
  string offer_unit_price = 4;
  // If true, this item's price is not calculated ("Price on Application").
  // All monetary fields in the corresponding PricedLineItem response will be
  // empty strings.
  bool price_on_application = 5;
  // A list of discounts to be applied to this line item.
  repeated Discount discounts = 6;
  // The applicable tax rate for this item, as a percentage string (e.g., "8.25"
  // for 8.25%).
  string tax_rate = 7;
}

// DiscountValue captures the detailed results of applying one or more discounts.
message DiscountValue {
  // The total monetary value of the discount applied, as a decimal string.
  string amount = 1;
  // The effective total percentage of the discount, calculated after all stacking.
  string percentage = 2;
  // The individual percentage contributions from each discount tier factor.
  // This is useful for auditing how a chained discount was constructed.
  repeated string factor_percentages = 3;
}

// PricedLineItem represents a line item after all pricing calculations have
// been performed.
message PricedLineItem {
  // The SKU, carried over from the request for identification.
  string sku = 1;
  // The final unit price used for calculation after promo-min selection.
  string unit_price = 2;
  // The offer unit price from the request, for reference.
  string offer_unit_price = 3;
  // The final payable amount for the line item *before* tax (Net).
  // This is (unit_price * quantity) - discounts.
  string net_payable = 4;
  // The detailed breakdown of the discount applied to the net amount.
  DiscountValue discount_value = 5;
  // The total tax amount calculated for the line item.
  string tax_value = 6;
  // The final payable amount for the line item *including* tax (Gross).
  // This is net_payable + tax_value.
  string net_payable_with_tax = 7;
  // The detailed breakdown of the discount as applied to the gross amount.
  // This is populated when discounts are applied post-tax.
  DiscountValue discount_value_with_tax = 8;
  // If true, indicates this item was "Price on Application" and no pricing
  // was performed. All monetary fields will be empty strings.
  bool price_on_application = 9;
}

// ComputeBasketRequest is the input for the pricing calculation RPC.
message ComputeBasketRequest {
  // The list of line items to be priced. Must not be empty.
  repeated LineItem items = 1;
  // The strategy for combining multiple discount tiers (e.g., CHAIN or ADDITION).
  DiscountStrategy strategy = 2;
  // The currency context for all calculations. Must be provided.
  Currency currency = 3;
  // A flag to control whether tax calculations should be performed.
  bool calculate_tax = 4;
  // A flag to control the order of operations:
  // true: Discounts are applied to the net price, then tax is added.
  // false: Tax is added to the base price, then discounts are applied to the gross price.
  bool discounts_pre_tax = 5;
}

// ComputeBasketResponse is the output of the pricing calculation RPC.
message ComputeBasketResponse {
  // The list of priced line items, corresponding one-to-one with the request items.
  repeated PricedLineItem items = 1;
  // The sum of `net_payable` across all priced line items.
  string subtotal_net_payable = 2;
  // The sum of `net_payable_with_tax` across all priced line items.
  string subtotal_net_payable_with_tax = 3;
}
```

